func warehouseStockTitle(vm WarehouseStockVM) string {
	if vm.Report == nil {
		return "Warehouse Stock"
	}
	return vm.Report.Warehouse.Name + " Stock"
}

func warehouseStockItemStatusClass(row services.WarehouseStockRow) string {
	const base = "inline-block rounded px-2 py-0.5 text-small font-medium "
	if !row.IsActive {
		return base + "bg-background text-text-muted border border-border"
	}
	if row.QuantityOnHand.IsPositive() {
		return base + "bg-success-soft text-success-hover border border-success-border"
	}
	return base + "bg-surface-tableHeader text-text-muted2 border border-border"
}

func warehouseStockItemStatusLabel(row services.WarehouseStockRow) string {
	if !row.IsActive {
		return "Inactive"
	}
	if row.QuantityOnHand.IsPositive() {
		return "In stock"
	}
	return "Zero"
}

